import{_ as t,c as o,o as a,a5 as i,f2 as s,f3 as n,f4 as p,f5 as c,f6 as d,f7 as r,f8 as l,f9 as u,fa as h,fb as m,fc as g,fd as f,fe as _,ff as b,fg as P,fh as y}from"./chunks/framework.BgIqBWih.js";const R=JSON.parse('{"title":"Python Session Plugin","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide-python.md","filePath":"docs/guide-python.md","lastUpdated":1772777937000}'),S={name:"docs/guide-python.md"};function k(v,e,x,E,T,w){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="python-session-plugin" tabindex="-1">Python Session Plugin <a class="header-anchor" href="#python-session-plugin" aria-label="Permalink to “Python Session Plugin”">​</a></h1><p>In Liii STEM, you can run Python code by inserting a <strong>Python session</strong> block.</p><h3 id="enter-a-python-session" tabindex="-1">Enter a Python session <a class="header-anchor" href="#enter-a-python-session" aria-label="Permalink to “Enter a Python session”">​</a></h3><p>First, make sure Python is installed on your computer. Then click <code>Insert session</code> -&gt; <code>Python</code> in the mode toolbar.</p><p><img src="'+s+'" alt=""></p><p>After first insertion, the page will look like this:</p><p><img src="'+n+'" alt=""></p><h3 id="run-code" tabindex="-1">Run code <a class="header-anchor" href="#run-code" aria-label="Permalink to “Run code”">​</a></h3><p>Type code in the block and run it.</p><p><img src="'+p+'" alt=""></p><p>Liii STEM supports all available conda environments.</p><h2 id="plugin-usage-notes" tabindex="-1">Plugin usage notes <a class="header-anchor" href="#plugin-usage-notes" aria-label="Permalink to “Plugin usage notes”">​</a></h2><p>Open <code>Help</code> -&gt; <code>Plugins</code> -&gt; <code>Python</code> to view the full plugin guide.</p><p><img src="'+c+'" alt=""></p><h3 id="statement-input" tabindex="-1">Statement input <a class="header-anchor" href="#statement-input" aria-label="Permalink to “Statement input”">​</a></h3><p>Use <code>Shift</code> + <code>Return/Enter</code> to separate statements.</p><p><img src="'+d+'" alt=""></p><p>When ready to evaluate code, press <code>Enter</code> / <code>Return</code>.</p><p><img src="'+r+'" alt=""></p><p>For multi-line input, enable <code>Focus</code> -&gt; <code>Input options</code> -&gt; <code>Multiline input</code>, then use <code>Enter</code> to add new lines.</p><p><img src="'+l+'" alt=""></p><p><img src="'+u+'" alt=""></p><blockquote><p>If you see the state above, multiline input is enabled.</p></blockquote><h3 id="command-auto-completion" tabindex="-1">Command auto-completion <a class="header-anchor" href="#command-auto-completion" aria-label="Permalink to “Command auto-completion”">​</a></h3><p>Type the first character(s) of built-in or previously defined commands, then press <code>Tab</code> to cycle suggestions.</p><p><img src="'+h+'" alt=""></p><h3 id="postscript-output-and-matplotlib-support" tabindex="-1">PostScript output and matplotlib support <a class="header-anchor" href="#postscript-output-and-matplotlib-support" aria-label="Permalink to “PostScript output and matplotlib support”">​</a></h3><p>Use <code>ps_out(data)</code> to output PostScript data directly to TeXmacs/Liii STEM:</p><ul><li>If <code>data</code> is a multi-line string, it is treated as raw PostScript.</li><li>If <code>data</code> is a single-line string, it is treated as a PostScript file path (<code>.eps</code>/<code>.ps</code> can be inferred).</li><li>If <code>data</code> is a <code>matplotlib.pyplot.Figure</code> (with a PS-capable backend), the plugin calls <code>savefig()</code> and inserts the output.</li><li>If <code>data</code> has a <code>read</code> method, PostScript is read from it.</li></ul><h3 id="help-popup" tabindex="-1">Help popup <a class="header-anchor" href="#help-popup" aria-label="Permalink to “Help popup”">​</a></h3><p>If object source code is available via <code>inspect.getsource()</code>, typing the object name followed by <code>?</code> opens a popup with <code>help()</code> and source.</p><h3 id="as-a-scripting-language" tabindex="-1">As a scripting language <a class="header-anchor" href="#as-a-scripting-language" aria-label="Permalink to “As a scripting language”">​</a></h3><p>Click <code>Insert</code> -&gt; <code>Fold</code> -&gt; <code>Executable</code> -&gt; <code>Python</code> to create a runnable field:</p><p><img src="'+m+'" alt=""></p><p><img src="'+g+'" alt=""></p><p>Enter Python expressions/statements in the yellow box:</p><p><img src="'+f+'" alt=""></p><p>Press <code>Return</code> / <code>Enter</code> to toggle between raw input and evaluated output.</p><p><img src="'+_+'" alt=""></p><p>For complex code, use <code>Shift</code> + <code>Return/Enter</code> for multiline input.</p><p>Note:</p><ul><li>Expressions are evaluated via <code>eval()</code> and can return inline output.</li><li>Statements are compiled via <code>compile()</code>; the final return value is not shown.</li><li>For inline output in statement-heavy code, write to <code>os.sys.stdout</code>.</li></ul><p>You can also use <code>Document</code> -&gt; <code>Scripts</code> -&gt; <code>Python</code>, or insert evaluable fields via <code>Insert</code> -&gt; <code>Link</code>.</p><p><img src="'+b+'" alt=""></p><p><img src="'+P+'" alt=""></p><p>Again, <code>Return/Enter</code> toggles calculated vs. uncalculated view.</p><p><img src="'+y+'" alt=""></p>',47)])])}const A=t(S,[["render",k]]);export{R as __pageData,A as default};
